```go
package main

import (
    "database/sql"
    "fmt"

    _ "github.com/mattn/go-sqlite3" // Import your database driver
)

// Customer represents a customer in the database.
type Customer struct {
    ID       int    `json:"id"`
    Status   string `json:"status"`
    City     string `json:"city"`
    SignupYear int    `json:"signup_year"`
}

func main() {
    // Connect to your database
    db, err := sql.Open("sqlite3", "./example.db")
    if err != nil {
        panic(err)
    }
    defer db.Close()

    // Create a map of optional filters
    filters := map[string]interface{}{
        "status":  "active",
        "city":     "New York",
        "signup_year": 2020,
    }

    // Query the customers table with optional filters
    query, err := db.Prepare("SELECT * FROM customers")
    if err != nil {
        panic(err)
    }
    defer query.Close()

    rows, err := query.Query()
    if err != nil {
        panic(err)
    }
    defer rows.Close()

    // Iterate over the results and print each customer
    for rows.Next() {
        var customer Customer
        err = rows.Scan(&customer.ID, &customer.Status, &customer.City, &customer.SignupYear)
        if err != nil {
            panic(err)
        }

        // Only add WHERE clauses for keys that are set in the filters map
        whereClauses := make([]string, 0, len(filters))
        for key, value := range filters {
            if value != "" {
                whereClauses = append(whereClauses, fmt.Sprintf("%s = ?", key))
            }
        }

        // If there are WHERE clauses, execute them
        if len(whereClauses) > 0 {
            _, err = query.Exec(whereClauses...)
            if err != nil {
                panic(err)
            }
        }

        // Print the customer
        fmt.Printf("ID: %d, Status: %s, City: %s, Signup Year: %d\n", customer.ID, customer.Status, customer.City, customer.SignupYear)
    }

    // Check for any errors
    err = rows.Err()
    if err != nil {
        panic(err)
    }
}
