// InsertUser inserts a new user row into the users table.
func InsertUser(db *sql.DB, fields map[string]interface{}) (int64, error) {
    // Create a new user struct to hold the fields
    type User struct {
        Name  string
        Email string
        Phone string
    }

    // Unpack the fields map into the user struct
    var user User
    for field, value := range fields {
        switch field {
        case "name":
            user.Name = value.(string)
        case "email":
            user.Email = value.(string)
        case "phone":
            user.Phone = value.(string)
        default:
            return 0, sql.ErrFieldUnknown
        }
    }

    // Prepare the SQL statement to insert a new user row
    stmt, err := db.Prepare("INSERT INTO users (name, email, phone) VALUES (?, ?, ?)")
    if err != nil {
        return 0, err
    }
    defer stmt.Close()

    // Execute the SQL statement with the user fields
    _, err = stmt.Exec(user.Name, user.Email, user.Phone)
    if err != nil {
        return 0, err
    }

    // Get the ID of the newly inserted row
    id := stmt.LastInsertId()
    return id, nil
}

