                    'id': user_data[0],
                    'name': user_data[1],
                    'email': user_data[2]
                }
            else:
                return None
        except sqlite3.Error as e:
            print(f"An error occurred: {e}")
            return None

    def close_connection(self):
        self.conn.close()

