use rusqlite::{Connection, Error};

// Define a struct to represent a user
#[derive(Debug)]
struct User {
    id: String,
    name: String,
    email: String,
}

impl User {
    fn new(id: &str, name: &str, email: &str) -> Self {
        User { id: id.to_string(), name: name.to_string(), email: email.to_string() }
    }

    // Function to retrieve a user's row from the database
    async fn get_user(&self, conn: &Connection) -> Result<Option<User>, Error> {
        let query = "SELECT * FROM users WHERE id = ?";

        let stmt = conn.prepare(query).map_err(|e| e.to_string())?;
        let result = stmt.query_map([&self.id], |row| {
            let id = row.get(0)?;
            let name = row.get(1)?;
            let email = row.get(2)?;

            Ok(User::new(id, name, email))
        }).map_err(|e| e.to_string())?;

        if result.is_empty() {
            return Ok(None);
        }

        Ok(Some(result[0]))
    }
}

fn main() -> Result<(), Error> {
    // Create a new SQLite database
    let conn = Connection::open("users.db")?;

    // Insert some data into the database
    conn.execute(
        "CREATE TABLE IF NOT EXISTS users (
            id TEXT PRIMARY KEY,
            name TEXT NOT NULL,
            email TEXT NOT NULL
        )",
        [],
    )?;

    conn.execute(
        "INSERT INTO users (id, name, email) VALUES (?, ?, ?)",
        ["user1", "John Doe", "john@example.com"],
    )?;

    // Retrieve a user's row from the database
    let user = User::new("user2", "Jane Doe", "jane@example.com");
    match user.get_user(&conn).await {
        Ok(Some(user)) => println!("User found: {:?}", user),
        Ok(None) => println!("No user found"),
        Err(e) => eprintln!("Error: {}", e),
    }

    // Close the database connection
    conn.close()?;

    Ok(())
}
