package main

import (
	"database/sql"
	"fmt"
	"strings"
)

// Customer represents a customer record.
type Customer struct {
	ID          int
	Name        string
	Email       string
	Status      string
	City        string
	SignupYear  int
}

// FindCustomers queries the customers table with optional filters.
func FindCustomers(db *sql.DB, filters map[string]string) ([]Customer, error) {
	// Build the SQL query
	var query strings.Builder
	query.WriteString("SELECT * FROM customers")

	// Build the WHERE clause
	var whereClauses []string
	if len(filters) > 0 {
		query.WriteString(" WHERE ")
		for key, value := range filters {
			switch key {
			case "status":
				whereClauses = append(whereClauses, fmt.Sprintf("status = '%s'", value))
			case "city":
				whereClauses = append(whereClauses, fmt.Sprintf("city = '%s'", value))
			case "signup_year":
				whereClauses = append(whereClauses, fmt.Sprintf("signup_year = %s", value))
			default:
				// Ignore unknown filter keys
			}
		}
		query.WriteString(strings.Join(whereClauses, " AND "))
	}

	// Execute the query
	rows, err := db.Query(query.String())
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	// Scan the rows into Customer objects
	var customers []Customer
	for rows.Next() {
		var c Customer
		if err := rows.Scan(
			&c.ID,
			&c.Name,
			&c.Email,
			&c.Status,
			&c.City,
			&c.SignupYear,
		); err != nil {
			return nil, err
		}
		customers = append(customers, c)
	}

	if err := rows.Err(); err != nil {
		return nil, err
	}

	return customers, nil
}
