Here's a Go function that retrieves orders by their IDs using a single SQL query with an `IN` clause, using the `database/sql` package:

```go
package main

import (
	"database/sql"
	"fmt"
)

// Order represents an order from the database
type Order struct {
	ID          int
	CustomerID  int
	TotalAmount float64
	CreatedAt   string
}

// GetOrdersByIDs retrieves orders by their IDs using a single query
func GetOrdersByIDs(db *sql.DB, orderIDs []int) ([]Order, error) {
	if len(orderIDs) == 0 {
		return []Order{}, nil
	}

	// Prepare the SQL query with an IN clause
	query := "SELECT * FROM orders WHERE id IN (" + placeholders(len(orderIDs)) + ")"
	rows, err := db.Query(query, orderIDs...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var orders []Order
	for rows.Next() {
		var order Order
		if err := rows.Scan(&order.ID, &order.CustomerID, &order.TotalAmount, &order.CreatedAt); err != nil {
			return nil, err
		}
		orders = append(orders, order)
	}

	if err := rows.Err(); err != nil {
		return nil, err
	}

	return orders, nil
}

// placeholders generates a string of question marks for the IN clause
func placeholders(n int) string {
	if n == 0 {
		return ""
	}
	result := make([]byte, 0, n)
	for i := 0; i < n; i++ {
		if i > 0 {
			result = append(result, ',')
		}
		result = append(result, '?')
	}
	return string(result)
}
