// CreateUserFromForm inserts a new user into the users table and returns the new user ID.
func CreateUserFromForm(db *sql.DB, form map[string]string) (int64, error) {
	// Define the SQL query to insert a new user
	query := `
		INSERT INTO users (name, email) 
		VALUES (?, ?)
	`

	// Prepare the statement
	stmt, err := db.Prepare(query)
	if err != nil {
		return 0, fmt.Errorf("failed to prepare statement: %w", err)
	}
	defer stmt.Close()

	// Execute the insert
	result, err := stmt.Exec(form["name"], form["email"])
	if err != nil {
		return 0, fmt.Errorf("failed to insert user: %w", err)
	}

	// Get the last inserted ID
	lastInsertID, err := result.LastInsertId()
	if err != nil {
		return 0, fmt.Errorf("failed to get last insert ID: %w", err)
	}

	return lastInsertID, nil
}
```

